import type { NavigablePage } from 'nordic-pages-discovery';

import { getDiscoveredNordicPages } from 'nordic-pages-discovery';

export function readDiscoveryEntrypoints() {
  const discoveryManifest = getDiscoveredNordicPages();
  const entrypoints = new Set<string>();

  if (!discoveryManifest) {
    return entrypoints;
  }

  const addEntrypointsByPage = ({ paths }: Pick<NavigablePage, 'paths'>) =>
    Object.values(paths).forEach(
      ({ client }) => client && entrypoints.add(client),
    );

  discoveryManifest.discoveredNavigablePages.forEach(addEntrypointsByPage);

  Object.values(discoveryManifest.discoveredHttpErrorPages).forEach(
    addEntrypointsByPage,
  );

  return entrypoints;
}
